	,make: function(sh) {
		if(this.shared == sh) {
			sh = null;
		}
		if(sh != null || !this.shared.isInstance) {
			return this.makeClone(sh);
		}
		if(!this.shouldBeInstanciated()) {
			return this;
		}
		if(this.shared.root3d == null) {
			this.shared.root3d = this.shared.current3d = new h3d.scene.Object();
		}
		return this.__makeInternal();
	}
