	,coordToDir: function(ij) {
		var i = ij.x;
		var sign = i >= 0 ? "+" : "-";
		if(i < 0) {
			i = -i;
		}
		var i1 = ij.y;
		var sign1 = i1 >= 0 ? "+" : "-";
		if(i1 < 0) {
			i1 = -i1;
		}
		var chunk = "L0_" + ("" + sign + i) + "_" + ("" + sign1 + i1);
		return new haxe.io.Path(this.datPath + chunk + "/");
	}
